import React from "react";
import { MainLayout } from "../layouts";

const AboutPage = () => {
  return (
    <MainLayout>
      <div className="about-page">
        <h1>Giới thiệu</h1>
        <p>Thông tin về hệ thống G-Bridge</p>
      </div>
    </MainLayout>
  );
};

export default AboutPage;
